import{_ as e,o as i,c as a,ao as s}from"./chunks/framework.DGf-9kxS.js";const p=JSON.parse('{"title":"What can I fit today?","description":"","frontmatter":{},"headers":[],"relativePath":"model-guides/model-map.md","filePath":"model-guides/model-map.md","lastUpdated":null}'),r={name:"model-guides/model-map.md"};function d(o,t,l,n,h,c){return i(),a("div",null,[...t[0]||(t[0]=[s(`<h1 id="What-can-I-fit-today?" tabindex="-1">What can I fit today? <a class="header-anchor" href="#What-can-I-fit-today?" aria-label="Permalink to &quot;What can I fit today? {#What-can-I-fit-today?}&quot;">​</a></h1><p>This page is the <strong>map of the model space</strong> DRM.jl covers — the overview for the Model Guides. It mirrors drmTMB&#39;s <a href="https://itchyshin.github.io/drmTMB/articles/model-map.html" target="_blank" rel="noreferrer">What can I fit today?</a>, and points you at the guide or tutorial for each piece. Read it top to bottom for the big picture, or jump to the <a href="/DRM.jl/dev/model-guides/model-map#Which-page-next">which page next</a> table.</p><h2 id="The-one-idea:-a-formula-per-parameter" tabindex="-1">The one idea: a formula per parameter <a class="header-anchor" href="#The-one-idea:-a-formula-per-parameter" aria-label="Permalink to &quot;The one idea: a formula per parameter {#The-one-idea:-a-formula-per-parameter}&quot;">​</a></h2><p>DRM.jl is <strong>distributional regression</strong> — you put predictors on <em>every</em> parameter of the response distribution, not just the mean. Each parameter gets its own formula, bundled together with <a href="/DRM.jl/dev/reference/model-specification#DRM.bf"><code>bf</code></a>:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Parameter</th><th style="text-align:right;">What it controls</th><th style="text-align:right;">Formula</th></tr></thead><tbody><tr><td style="text-align:right;"><strong>μ</strong> (mean / location)</td><td style="text-align:right;">where the response sits</td><td style="text-align:right;">the response formula, <code>y ~ …</code></td></tr><tr><td style="text-align:right;"><strong><code>sigma</code></strong> (scale / dispersion)</td><td style="text-align:right;">how spread out it is</td><td style="text-align:right;"><code>sigma ~ …</code></td></tr><tr><td style="text-align:right;">family extras — <code>nu</code>, <code>zi</code>, <code>hu</code>, <code>zoi</code>, <code>coi</code></td><td style="text-align:right;">shape, zero-inflation, hurdle, boundary mass</td><td style="text-align:right;"><code>nu ~ …</code>, <code>zi ~ …</code>, …</td></tr><tr><td style="text-align:right;"><strong><code>rho12</code></strong> (bivariate only)</td><td style="text-align:right;">residual correlation between two responses</td><td style="text-align:right;"><code>rho12 ~ …</code></td></tr></tbody></table><p>Always write <code>sigma</code> (never <code>tau</code>) for the scale and <code>rho12</code> for residual correlation. The same machinery drives every parameter: a formula → a linear predictor → a family-specific link. Which parameters are <em>available</em> depends on the family (Gaussian has no <code>nu</code>; only counts take <code>zi</code> / <code>hu</code>).</p><p>See <a href="./which-scale">Which scale are you modelling?</a> for the difference between the residual <code>sigma</code>, a group-level SD, and a known sampling variance — they are distinct quantities DRM.jl keeps separate.</p><h2 id="The-bf...-front-end" tabindex="-1">The <code>bf(...)</code> front end <a class="header-anchor" href="#The-bf...-front-end" aria-label="Permalink to &quot;The \`bf(...)\` front end {#The-bf...-front-end}&quot;">​</a></h2><p><a href="/DRM.jl/dev/reference/model-specification#DRM.bf"><code>bf</code></a> (alias <code>drm_formula</code>) collects one formula per parameter and reads exactly like drmTMB and brms. It has two forms:</p><p><strong>Univariate — positional.</strong> The first formula is the mean; the rest name their parameter on the left-hand side:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@formula</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@formula</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sigma </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x))                 </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># mean + scale</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@formula</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@formula</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sigma </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@formula</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(nu </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># + shape (Student)</span></span></code></pre></div><p><strong>Bivariate — keyword.</strong> Name each of the two responses&#39; parameters explicitly, including the residual correlation <code>rho12</code>:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(mu1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> @formula</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(y1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x), mu2 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> @formula</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(y2 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x),</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   sigma1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> @formula</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sigma1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), sigma2 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> @formula</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sigma2 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   rho12 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> @formula</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(rho12 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x))</span></span></code></pre></div><p>You pass the bundle and a family to <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#DRM.drm"><code>drm</code></a>: <code>drm(bf(...), Gaussian(); data = dat)</code>. ML is the default (REML likelihoods are not comparable across fixed-effect structures, so ML is what model selection needs). For the full grammar — including <code>cbind(successes, failures) ~ …</code> for binomial-type responses — see the <a href="./../reference/model-specification">model specification reference</a>.</p><h2 id="Supported-families" tabindex="-1">Supported families <a class="header-anchor" href="#Supported-families" aria-label="Permalink to &quot;Supported families {#Supported-families}&quot;">​</a></h2><p>Pick the family from the <em>shape</em> of the response; the <a href="./distribution-families">Choosing response families</a> guide has the full decision table and worked examples. DRM.jl implements drmTMB&#39;s complete family set:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Family</th><th style="text-align:right;">Response</th><th style="text-align:right;">Mean link</th><th style="text-align:right;"><code>sigma</code> slot / extras</th></tr></thead><tbody><tr><td style="text-align:right;"><a href="/DRM.jl/dev/reference/model-specification#DRM.Gaussian"><code>Gaussian</code></a></td><td style="text-align:right;">real-valued, symmetric</td><td style="text-align:right;">identity</td><td style="text-align:right;">residual SD <code>σ</code> (log)</td></tr><tr><td style="text-align:right;"><a href="/DRM.jl/dev/reference/model-specification#DRM.Student"><code>Student</code></a></td><td style="text-align:right;">real-valued, heavy tails</td><td style="text-align:right;">identity</td><td style="text-align:right;">scale <code>σ</code> + d.o.f. <code>nu</code></td></tr><tr><td style="text-align:right;"><a href="/DRM.jl/dev/reference/model-specification#DRM.LogNormal"><code>LogNormal</code></a></td><td style="text-align:right;">positive, multiplicative</td><td style="text-align:right;">identity on <code>log y</code></td><td style="text-align:right;">SD of <code>log y</code></td></tr><tr><td style="text-align:right;"><a href="/DRM.jl/dev/reference/model-specification#DRM.Gamma"><code>Gamma</code></a></td><td style="text-align:right;">positive, continuous</td><td style="text-align:right;">log</td><td style="text-align:right;">CV → shape <code>α = 1/σ²</code></td></tr><tr><td style="text-align:right;"><a href="/DRM.jl/dev/reference/model-specification#DRM.Tweedie"><code>Tweedie</code></a></td><td style="text-align:right;">positive <strong>with exact zeros</strong></td><td style="text-align:right;">log</td><td style="text-align:right;">√dispersion <code>σ</code> + power <code>nu</code> ∈ (1,2)</td></tr><tr><td style="text-align:right;"><a href="/DRM.jl/dev/reference/model-specification#DRM.Poisson"><code>Poisson</code></a></td><td style="text-align:right;">counts (var ≈ mean)</td><td style="text-align:right;">log</td><td style="text-align:right;">— (<code>+ zi</code> / <code>+ hu</code>)</td></tr><tr><td style="text-align:right;"><a href="/DRM.jl/dev/reference/model-specification#DRM.NegBinomial2"><code>NegBinomial2</code></a></td><td style="text-align:right;">overdispersed counts (NB2)</td><td style="text-align:right;">log</td><td style="text-align:right;">dispersion <code>θ</code> (<code>+ zi</code> / <code>+ hu</code>)</td></tr><tr><td style="text-align:right;"><a href="/DRM.jl/dev/reference/model-specification#DRM.TruncatedNegBinomial2"><code>TruncatedNegBinomial2</code></a></td><td style="text-align:right;">positive counts (≥ 1)</td><td style="text-align:right;">log</td><td style="text-align:right;">dispersion <code>θ</code></td></tr><tr><td style="text-align:right;"><a href="/DRM.jl/dev/reference/model-specification#DRM.Beta"><code>Beta</code></a></td><td style="text-align:right;">proportions in (0,1)</td><td style="text-align:right;">logit</td><td style="text-align:right;">precision <code>φ = 1/σ²</code></td></tr><tr><td style="text-align:right;"><a href="/DRM.jl/dev/reference/model-specification#DRM.BetaBinomial"><code>BetaBinomial</code></a></td><td style="text-align:right;">successes / trials, overdispersed</td><td style="text-align:right;">logit</td><td style="text-align:right;"><code>φ = 1/σ²</code> (<code>cbind</code>)</td></tr><tr><td style="text-align:right;"><a href="/DRM.jl/dev/reference/model-specification#DRM.Binomial"><code>Binomial</code></a></td><td style="text-align:right;">successes / trials</td><td style="text-align:right;">logit</td><td style="text-align:right;">— (<code>cbind</code> or 0/1)</td></tr><tr><td style="text-align:right;"><a href="/DRM.jl/dev/reference/model-specification#DRM.ZeroOneBeta"><code>ZeroOneBeta</code></a></td><td style="text-align:right;">proportions on <code>[0,1]</code> incl. 0 and 1</td><td style="text-align:right;">logit</td><td style="text-align:right;"><code>φ</code> + <code>zoi</code> / <code>coi</code></td></tr><tr><td style="text-align:right;"><a href="/DRM.jl/dev/reference/model-specification#DRM.CumulativeLogit"><code>CumulativeLogit</code></a></td><td style="text-align:right;">ordered categories <code>1..K</code></td><td style="text-align:right;">logit (cutpoints)</td><td style="text-align:right;">K−1 ordered cutpoints</td></tr></tbody></table><p>The count modifiers — <code>zi</code> (zero-inflation, ZIP / ZINB), <code>hu</code> (hurdle), and the beta boundary modifiers <code>zoi</code> / <code>coi</code> — are themselves formulas you add to the bundle, e.g. <code>bf(@formula(y ~ x), @formula(zi ~ 1))</code>.</p><h2 id="Structured-and-random-effects" tabindex="-1">Structured and random effects <a class="header-anchor" href="#Structured-and-random-effects" aria-label="Permalink to &quot;Structured and random effects {#Structured-and-random-effects}&quot;">​</a></h2><p>On top of fixed effects, DRM.jl carries ordinary random effects and several <strong>structured</strong> effects whose covariance comes from a known matrix or geometry. Write them as terms in the mean formula:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Effect</th><th style="text-align:right;">Term</th><th style="text-align:right;">What it encodes</th></tr></thead><tbody><tr><td style="text-align:right;">Random intercept / slope</td><td style="text-align:right;"><code>(1 | g)</code>, <code>(0 + x | g)</code>, <code>(1 + x | g)</code></td><td style="text-align:right;">exchangeable group variation; correlated slopes</td></tr><tr><td style="text-align:right;">Crossed / nested RE</td><td style="text-align:right;"><code>(1 | g) + (1 | h)</code></td><td style="text-align:right;">multiple grouping factors</td></tr><tr><td style="text-align:right;"><a href="/DRM.jl/dev/reference/structured-effect-markers#DRM.phylo"><code>phylo</code></a></td><td style="text-align:right;"><code>phylo(1 | species)</code></td><td style="text-align:right;">covariance from a phylogenetic tree</td></tr><tr><td style="text-align:right;"><a href="/DRM.jl/dev/reference/structured-effect-markers#DRM.spatial"><code>spatial</code></a></td><td style="text-align:right;"><code>spatial(1 | site)</code></td><td style="text-align:right;">exponential kernel over coordinates, estimated range</td></tr><tr><td style="text-align:right;"><a href="/DRM.jl/dev/reference/structured-effect-markers#DRM.animal"><code>animal</code></a></td><td style="text-align:right;"><code>animal(1 | id)</code></td><td style="text-align:right;">additive-genetic covariance from a pedigree <code>A</code></td></tr><tr><td style="text-align:right;"><a href="/DRM.jl/dev/reference/structured-effect-markers#DRM.relmat"><code>relmat</code></a></td><td style="text-align:right;"><code>relmat(1 | id)</code></td><td style="text-align:right;">a user-supplied relatedness matrix <code>K</code></td></tr><tr><td style="text-align:right;"><a href="/DRM.jl/dev/reference/structured-effect-markers#DRM.meta_V"><code>meta_V</code></a></td><td style="text-align:right;"><code>meta_V(v)</code></td><td style="text-align:right;">known sampling (co)variances for meta-analysis</td></tr></tbody></table><p><strong>Which families route which effects.</strong> Gaussian gets the full set — random intercept/slope, correlated and crossed RE, phylo / spatial / animal / relmat structure, <code>meta_V</code>, and a random effect <em>on</em> <code>sigma</code> — fit in closed form or via a sparse augmented-state Laplace approximation. The non-Gaussian families (Poisson, NB2, Binomial, Gamma, Beta, and the deeper Student-t / LogNormal / Beta-binomial GLMMs) carry random intercepts and correlated slopes via Gauss–Hermite marginals, and <strong>phylogenetic</strong> (<code>phylo</code>) effects via a sparse Laplace path — currently with a <strong>constant <code>sigma</code></strong>. So put predictors on <code>sigma</code> for Gaussian freely; for the count/proportion families, vary the mean and keep dispersion constant when adding a structured or phylogenetic effect.</p><p>For the verified engine behind the phylogenetic models — the q=4 phylogenetic bivariate location–scale model that fits 2.18× faster than drmTMB with valid intervals where its Hessian is singular — see <code>HANDOVER.md</code> and <a href="https://github.com/itchyshin/DRM.jl/blob/main/report/comparison-grid.md" target="_blank" rel="noreferrer"><code>report/comparison-grid.md</code></a>.</p><h2 id="After-the-fit" tabindex="-1">After the fit <a class="header-anchor" href="#After-the-fit" aria-label="Permalink to &quot;After the fit {#After-the-fit}&quot;">​</a></h2><p>Every fitted model supports the same post-fit surface: <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#StatsAPI.coef"><code>coef</code></a>, <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#StatsAPI.stderror"><code>stderror</code></a>, Wald <strong>and</strong> profile-likelihood <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#StatsAPI.confint"><code>confint</code></a>, <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#StatsAPI.fitted"><code>fitted</code></a> / <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#StatsAPI.residuals"><code>residuals</code></a>, <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#StatsAPI.predict"><code>predict</code></a>, <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#DRM.simulate"><code>simulate</code></a>, parametric <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#DRM.bootstrap_ci"><code>bootstrap_ci</code></a>, <code>summary</code> / <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#StatsAPI.coeftable"><code>coeftable</code></a>, and <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#StatsAPI.aic"><code>aic</code></a> / <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#StatsAPI.bic"><code>bic</code></a> for ML model selection. Variance components come back via <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#DRM.re_sd"><code>re_sd</code></a> (one SD per grouping) and <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#DRM.vc"><code>vc</code></a> (the RE covariance). See <a href="./model-workflow">Checking and using fitted models</a> for the workflow, and <a href="./which-scale">Which scale are you modelling?</a> for honest inference at a variance boundary (where drmTMB&#39;s <code>sdreport</code> returns all-<code>NaN</code>).</p><h2 id="Which-page-next" tabindex="-1">Which page next <a class="header-anchor" href="#Which-page-next" aria-label="Permalink to &quot;Which page next {#Which-page-next}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">If you want to…</th><th style="text-align:right;">Go to</th></tr></thead><tbody><tr><td style="text-align:right;">Fit your first model, end to end</td><td style="text-align:right;"><a href="./../get-started">Get started</a></td></tr><tr><td style="text-align:right;">Choose the right response family</td><td style="text-align:right;"><a href="./distribution-families">Choosing response families</a></td></tr><tr><td style="text-align:right;">Tell residual <code>σ</code>, group SD, and known V apart</td><td style="text-align:right;"><a href="./which-scale">Which scale are you modelling?</a></td></tr><tr><td style="text-align:right;">Extract coefficients, CIs, predictions</td><td style="text-align:right;"><a href="./model-workflow">Checking and using fitted models</a></td></tr><tr><td style="text-align:right;">Diagnose convergence</td><td style="text-align:right;"><a href="./convergence">Convergence</a></td></tr><tr><td style="text-align:right;">Scale to large data</td><td style="text-align:right;"><a href="./large-data">Large data</a></td></tr><tr><td style="text-align:right;">Choose the marginal method (Laplace vs VA)</td><td style="text-align:right;"><a href="./marginal-la-vs-va">Marginal: LA vs VA</a></td></tr><tr><td style="text-align:right;">Model variability as signal (location–scale)</td><td style="text-align:right;"><a href="./../tutorials/location-scale">When variance carries signal</a></td></tr><tr><td style="text-align:right;">Change residual coupling with <code>rho12</code></td><td style="text-align:right;"><a href="./../tutorials/bivariate-coscale">Changing residual coupling with rho12</a></td></tr><tr><td style="text-align:right;">Robust continuous responses</td><td style="text-align:right;"><a href="./../tutorials/robust-student">Robust continuous responses</a></td></tr><tr><td style="text-align:right;">Counts and extra zeros</td><td style="text-align:right;"><a href="./../tutorials/count-nbinom2">Count abundance and extra zeros</a></td></tr><tr><td style="text-align:right;">Proportions and success rates</td><td style="text-align:right;"><a href="./../tutorials/proportion-beta-binomial">Proportions and success rates</a></td></tr><tr><td style="text-align:right;">Phylogenetic / spatial / animal models</td><td style="text-align:right;"><a href="./../tutorials/phylogenetic-models">Phylogenetic</a> · <a href="./../tutorials/spatial-models">Spatial</a> · <a href="./../tutorials/animal-models">Animal</a></td></tr><tr><td style="text-align:right;">Meta-analysis with known variances</td><td style="text-align:right;"><a href="./../tutorials/meta-analysis">Meta-analysis</a></td></tr><tr><td style="text-align:right;">The full API reference</td><td style="text-align:right;"><a href="./../reference/model-specification">Model specification</a> · <a href="./../reference/model-fitting-and-postfit">Fitting &amp; post-fit</a></td></tr><tr><td style="text-align:right;">What&#39;s planned next</td><td style="text-align:right;">the <a href="https://github.com/itchyshin/DRM.jl/blob/main/ROADMAP.md" target="_blank" rel="noreferrer">roadmap</a></td></tr></tbody></table>`,27)])])}const f=e(r,[["render",d]]);export{p as __pageData,f as default};
